diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
index fc284bc61cce..b2574bd438b6 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -1581,6 +1581,79 @@ Instruction *InstCombinerImpl::visitAdd(BinaryOperator &I) {
   if (match(&I, m_c_BinOp(m_ZExt(m_Value(A)), m_SExt(m_Deferred(A)))) &&
       A->getType()->isIntOrIntVectorTy(1))
     return replaceInstUsesWith(I, Constant::getNullValue(I.getType()));
+  // (X / C) << N + (X % C) --> (X / C) * (2^N - C) + X
+  // where the shift left is represented as (X / C) * 2^N, and 2^N >= C
+  // This is valid because: (X/C)*2^N + X%C = (X/C)*2^N + (X - (X/C)*C) = (X/C)*(2^N-C) + X
+  {
+    Value *RemX, *MulOp;
+    APInt RemC, MulC;
+    bool RemIsSigned;
+    
+    // Helper lambda to match remainder
+    auto MatchRem = [&](Value *E) -> bool {
+      const APInt *AI;
+      RemIsSigned = false;
+      if (match(E, m_SRem(m_Value(RemX), m_APInt(AI)))) {
+        RemIsSigned = true;
+        RemC = *AI;
+        return true;
+      }
+      if (match(E, m_URem(m_Value(RemX), m_APInt(AI)))) {
+        RemC = *AI;
+        return true;
+      }
+      return false;
+    };
+    
+    // Helper lambda to match division
+    auto MatchDiv = [&](Value *E, Value *&DivOp, APInt &DivC) -> bool {
+      const APInt *AI;
+      if (RemIsSigned && match(E, m_SDiv(m_Value(DivOp), m_APInt(AI)))) {
+        DivC = *AI;
+        return true;
+      }
+      if (!RemIsSigned) {
+        if (match(E, m_UDiv(m_Value(DivOp), m_APInt(AI)))) {
+          DivC = *AI;
+          return true;
+        }
+      }
+      return false;
+    };
+    
+    // Helper lambda to match multiplication or shift
+    auto MatchMulOrShl = [&](Value *E) -> bool {
+      const APInt *AI;
+      if (match(E, m_Mul(m_Value(MulOp), m_APInt(AI)))) {
+        MulC = *AI;
+        return true;
+      }
+      if (match(E, m_Shl(m_Value(MulOp), m_APInt(AI)))) {
+        MulC = APInt(AI->getBitWidth(), 1);
+        MulC <<= *AI;
+        return true;
+      }
+      return false;
+    };
+    
+    // Match pattern: (X / C) * M + (X % C) or (X % C) + (X / C) * M
+    if (((MatchRem(LHS) && MatchMulOrShl(RHS)) ||
+         (MatchRem(RHS) && MatchMulOrShl(LHS))) &&
+        MulC.ugt(0)) {  // Ensure MulC is positive
+      Value *DivOp;
+      APInt DivC;
+      // Check that MulOp is (X / C) with the same divisor C
+      if (MatchDiv(MulOp, DivOp, DivC) &&
+          DivOp == RemX && DivC == RemC) {
+        // Check that MulC (2^N from shift) >= RemC (divisor)
+        // This ensures the remainder bits don't overlap with the shifted quotient
+        if (MulC.uge(RemC)) {
+          Value *NewMul = Builder.CreateMul(MulOp, ConstantInt::get(Ty, MulC - RemC));
+          return BinaryOperator::CreateAdd(NewMul, RemX);
+        }
+      }
+    }
+  }

   // A+B --> A|B iff A and B have no bits set in common.
   WithCache<const Value *> LHSCache(LHS), RHSCache(RHS);
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
index e1923a344179..badce7429772 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
@@ -3420,6 +3420,53 @@ Value *InstCombinerImpl::foldAndOrOfICmps(ICmpInst *LHS, ICmpInst *RHS,

   return foldAndOrOfICmpsUsingRanges(LHS, RHS, IsAnd);
 }
+// Helper functions to match division and remainder patterns for (X / C) * M | (X % C) optimization
+static bool MatchRemForDivMulOr(Value *E, Value *&Op, APInt &C, bool &IsSigned) {
+  const APInt *AI;
+  IsSigned = false;
+  if (match(E, m_SRem(m_Value(Op), m_APInt(AI)))) {
+    IsSigned = true;
+    C = *AI;
+    return true;
+  }
+  if (match(E, m_URem(m_Value(Op), m_APInt(AI)))) {
+    C = *AI;
+    return true;
+  }
+  return false;
+}
+
+static bool MatchDivForDivMulOr(Value *E, Value *&Op, APInt &C, bool IsSigned) {
+  const APInt *AI;
+  if (IsSigned && match(E, m_SDiv(m_Value(Op), m_APInt(AI)))) {
+    C = *AI;
+    return true;
+  }
+  if (!IsSigned) {
+    if (match(E, m_UDiv(m_Value(Op), m_APInt(AI)))) {
+      C = *AI;
+      return true;
+    }
+  }
+  return false;
+}
+
+// Matches multiplication or shift expression Op * C or Op << N where C is a constant.
+// Returns the constant value in C and the other operand in Op. Returns true if such a
+// match is found.
+static bool MatchMulOrShlForDivMulOr(Value *E, Value *&Op, APInt &C) {
+  const APInt *AI;
+  if (match(E, m_Mul(m_Value(Op), m_APInt(AI)))) {
+    C = *AI;
+    return true;
+  }
+  if (match(E, m_Shl(m_Value(Op), m_APInt(AI)))) {
+    C = APInt(AI->getBitWidth(), 1);
+    C <<= *AI;
+    return true;
+  }
+  return false;
+}

 // FIXME: We use commutative matchers (m_c_*) for some, but not all, matches
 // here. We should standardize that construct where it is needed or choose some
@@ -3505,6 +3552,36 @@ Instruction *InstCombinerImpl::visitOr(BinaryOperator &I) {
     Value *IncrementY = Builder.CreateAdd(Y, ConstantInt::get(Ty, 1));
     return BinaryOperator::CreateMul(X, IncrementY);
   }
+  // (X / C) << N | (X % C) --> (X / C) * (2^N - C) + X
+  // where the shift left is represented as (X / C) * 2^N, and 2^N >= C
+  // This is valid because: (X/C)*2^N + X%C = (X/C)*2^N + (X - (X/C)*C) = (X/C)*(2^N-C) + X
+  {
+    Value *RemX, *MulOp;
+    APInt RemC, MulC;
+    bool RemIsSigned;
+    
+    // Match pattern: (X / C) * M | (X % C) or (X % C) | (X / C) * M
+    if (((MatchRemForDivMulOr(Op0, RemX, RemC, RemIsSigned) &&
+          MatchMulOrShlForDivMulOr(Op1, MulOp, MulC)) ||
+         (MatchRemForDivMulOr(Op1, RemX, RemC, RemIsSigned) &&
+          MatchMulOrShlForDivMulOr(Op0, MulOp, MulC))) &&
+        MulC.ugt(0)) {  // Ensure MulC is positive
+      Value *DivOp;
+      APInt DivC;
+      // Check that MulOp is (X / C) with the same divisor C
+      if (MatchDivForDivMulOr(MulOp, DivOp, DivC, RemIsSigned) &&
+          DivOp == RemX && DivC == RemC) {
+        // Check that MulC (2^N from shift) >= RemC (divisor)
+        // This ensures the remainder bits don't overlap with the shifted quotient
+        if (MulC.uge(RemC)) {
+          Value *NewMul = Builder.CreateMul(MulOp, ConstantInt::get(Ty, MulC - RemC));
+          return BinaryOperator::CreateAdd(NewMul, RemX);
+        }
+      }
+    }
+  }
+
+

   // (A & C) | (B & D)
   Value *A, *B, *C, *D;

